CustomField.formula:
IF( New_Flow__c == true,
			Grand_Total__c,
			IF(TEXT(Sales_Invoice__r.Payment_Type__c )=='Credit',
						Grand_Total__c ,
						IF(Grand_Total_after_discount__c != 0.0 ,
									Grand_Total_after_discount__c - (Grand_Total_after_discount__c * Customer__r.Cash_Discount__c),
									Grand_Total__c - (Grand_Total__c * Customer__r.Cash_Discount__c)
								)
					)
		)
